mapper.delete:
DELETE ur
FROM auth_user_role ur
INNER JOIN auth_role r ON r.role_id = ur.role_id
WHERE ur.user_id = #{userId}
  AND r.role_code = #{roleCode}

mapper.select:
SELECT COUNT(1)
FROM auth_user_role ur
INNER JOIN auth_role r ON r.role_id = ur.role_id
WHERE ur.user_id = #{userId}
  AND r.role_code = #{roleCode}
